import React, { useState, useEffect, useCallback } from "react";
import { motion } from "framer-motion";
import { C } from "../../_utils/constants";
import { faqs as defaultFaqs } from "@/app/_utils/landingConstants";

interface SettingsTabProps {
  adminEmail: string;
}

export function SettingsTab({ adminEmail }: SettingsTabProps) {
  const [selectedLang, setSelectedLang] = useState<"tr" | "en">("tr");
  const [siteSettings, setSiteSettings] = useState<any>({
    package_durations: {
      "temel": { old: null, new: 6 },
      "premium": { old: null, new: 18 },
      "premium+": { old: null, new: 24 }
    },
    maintenance_mode: false,
    announcement_banner: { active: false, text: "" },
    announcement_banner_en: { active: false, text: "" },
    hero_texts: {
      title: "Unutamayacağı<br /><em style=\"color: #C9A84C; font-style: italic\">Bir Sürpriz</em> Yap",
      subtitle: "Birlikte geçirdiğiniz anıları ölümsüzleştiren, sadece size özel tasarlanmış bir web sitesi hediye et."
    },
    hero_texts_en: {
      title: "Make an Unforgettable<br /><em style=\"color: #C9A84C; font-style: italic\">Surprise</em>",
      subtitle: "Gift a custom-designed website that immortalizes the memories you shared together."
    },
    faq_texts: {
      label: "Sıkça Sorulan",
      heading: "Aklında <em style=\"color: #C9A84C; font-style: italic\">Soru mu Var?</em>"
    },
    faq_texts_en: {
      label: "Frequently Asked",
      heading: "Have a <em style=\"color: #C9A84C; font-style: italic\">Question?</em>"
    },
    faqs: defaultFaqs,
    faqs_en: [
      {
        q: "How does the process work after ordering?",
        a: "After ordering, a code is sent to your email. You activate your memory page with this code from your profile, then upload your photos and music easily through the panel."
      },
      {
        q: "Do I upload the photos and music myself?",
        a: "Yes, you can upload all photos, select music, and write your personal messages directly from the page settings dashboard."
      },
      {
        q: "Is it mobile compatible?",
        a: "Yes, all templates are fully responsive and optimized for a cinematic mobile view."
      }
    ],
    whatsapp_number: "905555555555",
    abandoned_cart_settings: {
      enabled: true,
      email_delay_hours: 12,
      email_subject: "Yarım Kalan Bir Hikaye Var... 🤍",
      email_body: "<div style=\"font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #333; line-height: 1.6;\">\n<h2 style=\"color: #C9A84C;\">Merhaba,</h2>\n<p>Birlikteydik sayfanı tasarlamaya başladığını gördük ancak henüz yayına almadın.</p>\n<p>Yarım kalan anılarını tamamlamak ve sayfanı ölümsüzleştirmek için tasarımına geri dön.</p>\n<div style=\"text-align: center; margin: 30px 0;\">\n<a href=\"https://birlikteydik.com/profil\" style=\"background-color: #C9A84C; color: #0B0F1A; padding: 14px 28px; text-decoration: none; border-radius: 40px; font-weight: bold; font-size: 16px;\">Tasarımı Tamamla ve Hayata Geçir</a>\n</div>\n</div>",
      delete_delay_hours: 72
    }
  });
  const [settingsLoading, setSettingsLoading] = useState(false);
  const [settingsSaving, setSettingsSaving] = useState(false);

  const fetchSiteSettings = useCallback(async () => {
    if (!adminEmail) return;
    setSettingsLoading(true);
    try {
      const res = await fetch(`/api/admin/site-settings?adminEmail=${encodeURIComponent(adminEmail)}`);
      const data = await res.json();
      if (res.ok && data.settings) {
        setSiteSettings((prev: any) => ({
          ...prev,
          ...data.settings,
          faq_texts: data.settings.faq_texts || prev.faq_texts,
          faqs: data.settings.faqs || prev.faqs,
          faq_texts_en: data.settings.faq_texts_en || prev.faq_texts_en,
          faqs_en: data.settings.faqs_en || prev.faqs_en
        }));
      }
    } catch (err) {
      console.error("Settings load error:", err);
    } finally {
      setSettingsLoading(false);
    }
  }, [adminEmail]);

  useEffect(() => {
    fetchSiteSettings();
  }, [fetchSiteSettings]);

  const handleSave = async () => {
    setSettingsSaving(true);
    try {
      const res = await fetch("/api/admin/site-settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ adminEmail, settings: siteSettings })
      });
      if (!res.ok) throw new Error();
      alert("Ayarlar başarıyla kaydedildi.");
    } catch {
      alert("Ayarlar kaydedilirken hata oluştu.");
    } finally {
      setSettingsSaving(false);
    }
  };

  const cardStyle: React.CSSProperties = {
    background: "rgba(255,255,255,0.035)",
    border: "1px solid rgba(255,255,255,0.08)",
    borderRadius: "20px",
    backdropFilter: "blur(16px)",
    WebkitBackdropFilter: "blur(16px)",
  };

  const isEnTab = selectedLang === "en";
  const currentBanner = isEnTab 
    ? (siteSettings?.announcement_banner_en || { active: false, text: "" }) 
    : (siteSettings?.announcement_banner || { active: false, text: "" });

  const currentHero = isEnTab 
    ? (siteSettings?.hero_texts_en || { title: "", subtitle: "" }) 
    : (siteSettings?.hero_texts || { title: "", subtitle: "" });

  const currentFaqTexts = isEnTab 
    ? (siteSettings?.faq_texts_en || { label: "", heading: "" }) 
    : (siteSettings?.faq_texts || { label: "", heading: "" });

  const currentFaqs = isEnTab 
    ? (siteSettings?.faqs_en || []) 
    : (siteSettings?.faqs || []);

  return (
    <motion.div
      key="settings"
      initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }}
      transition={{ duration: 0.35 }}
      style={{ maxWidth: "680px", margin: "0 auto", fontFamily: "Inter, 'Inter Fallback', sans-serif" }}
    >
      <div style={{ ...cardStyle, padding: "32px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "8px", flexWrap: "wrap", gap: "10px" }}>
          <h2 style={{ fontFamily: "'Cormorant Garamond', 'Cormorant Garamond Fallback', serif", fontSize: "24px", fontWeight: 600, color: C.text }}>
            Site <em style={{ color: C.gold, fontStyle: "italic" }}>Ayarları</em>
          </h2>

          {/* Language Selector Toggle */}
          <div style={{ display: "flex", gap: "4px", background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.06)", borderRadius: "8px", padding: "3px" }}>
            {[
              { key: "tr", label: "TR" },
              { key: "en", label: "EN" }
            ].map((lang) => (
              <button
                key={lang.key}
                type="button"
                onClick={() => setSelectedLang(lang.key as "tr" | "en")}
                style={{
                  padding: "4px 10px",
                  borderRadius: "5px",
                  border: "none",
                  background: selectedLang === lang.key ? C.gold : "transparent",
                  color: selectedLang === lang.key ? "#0B0F1A" : C.muted,
                  fontSize: "11px",
                  fontWeight: selectedLang === lang.key ? 600 : 400,
                  cursor: "pointer",
                  fontFamily: "var(--font-inter), sans-serif",
                  transition: "all 0.15s"
                }}
              >
                {lang.label}
              </button>
            ))}
          </div>
        </div>

        <p style={{ fontSize: "13px", color: C.muted, marginBottom: "28px", fontWeight: 300, lineHeight: 1.6 }}>
          Sitenin temel ayarlarını ve paket aktiflik sürelerini buradan güncelleyebilirsiniz.
        </p>

        {settingsLoading ? (
          <div style={{ textAlign: "center", padding: "48px", color: C.muted, fontSize: "13px" }}>
            <div style={{ width: "24px", height: "24px", border: `2px solid ${C.border}`, borderTopColor: C.gold, borderRadius: "50%", animation: "spin 0.7s linear infinite", margin: "0 auto 12px" }} />
            Ayarlar yükleniyor…
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
            {/* Package Durations */}
            <div style={{ padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
              <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>Paket Aktiflik Süreleri (Ay)</h4>
              
              {["temel", "premium", "premium+"].map((pkgName) => {
                const vals = siteSettings?.package_durations?.[pkgName] || { old: null, new: 12 };
                return (
                  <div key={pkgName} style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "12px" }}>
                    <div style={{ width: "100px", fontSize: "13px", color: C.text, textTransform: "capitalize" }}>{pkgName}</div>
                    <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
                      <label style={{ fontSize: "10px", color: C.muted }}>Eski (Opsiyonel)</label>
                      <input
                        type="number"
                        value={vals.old || ""}
                        onChange={(e) => {
                          const val = e.target.value === "" ? null : Number(e.target.value);
                          setSiteSettings((prev: any) => ({
                            ...prev,
                            package_durations: {
                              ...prev.package_durations,
                              [pkgName]: { ...prev.package_durations?.[pkgName], old: val }
                            }
                          }));
                        }}
                        style={{ width: "60px", padding: "6px", borderRadius: "6px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "12px" }}
                      />
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
                      <label style={{ fontSize: "10px", color: C.muted }}>Yeni</label>
                      <input
                        type="number"
                        value={vals.new || ""}
                        onChange={(e) => {
                          const val = e.target.value === "" ? 0 : Number(e.target.value);
                          setSiteSettings((prev: any) => ({
                            ...prev,
                            package_durations: {
                              ...prev.package_durations,
                              [pkgName]: { ...prev.package_durations?.[pkgName], new: val }
                            }
                          }));
                        }}
                        style={{ width: "60px", padding: "6px", borderRadius: "6px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "12px" }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Maintenance Mode & WhatsApp */}
            <div style={{ display: "flex", gap: "20px", flexWrap: "wrap" }}>
              <div style={{ flex: 1, padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
                <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>Bakım Modu</h4>
                <label style={{ display: "flex", alignItems: "center", gap: "10px", cursor: "pointer" }}>
                  <input
                    type="checkbox"
                    checked={siteSettings?.maintenance_mode || false}
                    onChange={(e) => {
                      const isChecked = e.target.checked;
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        maintenance_mode: isChecked,
                        maintenance_start_time: isChecked ? new Date().toISOString() : null
                      }));
                    }}
                    style={{ accentColor: C.gold, width: "16px", height: "16px" }}
                  />
                  <span style={{ fontSize: "13px", color: C.text }}>Siteyi Bakım Moduna Al</span>
                </label>
                {siteSettings?.maintenance_mode && siteSettings?.maintenance_start_time && (
                  <p style={{ fontSize: "11px", color: C.muted, marginTop: "8px" }}>
                    Bakım başlangıcı: {new Date(siteSettings.maintenance_start_time).toLocaleString("tr-TR")}
                  </p>
                )}
              </div>

              <div style={{ flex: 1, padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
                <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>WhatsApp Numarası</h4>
                <input
                  type="text"
                  value={siteSettings?.whatsapp_number || ""}
                  onChange={(e) => setSiteSettings((prev: any) => ({ ...prev, whatsapp_number: e.target.value }))}
                  placeholder="905555555555"
                  style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                />
              </div>
            </div>

            {/* Announcement Banner */}
            <div style={{ padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
              <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>Duyuru Banner'ı ({selectedLang.toUpperCase()})</h4>
              <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
                <label style={{ display: "flex", alignItems: "center", gap: "10px", cursor: "pointer" }}>
                  <input
                    type="checkbox"
                    checked={currentBanner.active || false}
                    onChange={(e) => {
                      const bannerKey = isEnTab ? "announcement_banner_en" : "announcement_banner";
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        [bannerKey]: { ...(prev[bannerKey] || {}), active: e.target.checked }
                      }));
                    }}
                    style={{ accentColor: C.gold, width: "16px", height: "16px" }}
                  />
                  <span style={{ fontSize: "13px", color: C.text }}>Banner'ı Aktif Et</span>
                </label>
                <input
                  type="text"
                  value={currentBanner.text || ""}
                  onChange={(e) => {
                    const bannerKey = isEnTab ? "announcement_banner_en" : "announcement_banner";
                    setSiteSettings((prev: any) => ({
                      ...prev,
                      [bannerKey]: { ...(prev[bannerKey] || {}), text: e.target.value }
                    }));
                  }}
                  placeholder={isEnTab ? "e.g. Valentine's Day Special 20% Off!" : "Örn: Sevgililer Gününe Özel %20 İndirim!"}
                  style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                />
              </div>
            </div>

            {/* Hero Texts */}
            <div style={{ padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
              <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>Ana Sayfa (Hero) Metinleri ({selectedLang.toUpperCase()})</h4>
              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Ana Başlık (HTML Kullanılabilir)</label>
                  <textarea
                    value={currentHero.title || ""}
                    onChange={(e) => {
                      const heroKey = isEnTab ? "hero_texts_en" : "hero_texts";
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        [heroKey]: { ...(prev[heroKey] || {}), title: e.target.value }
                      }));
                    }}
                    rows={3}
                    style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px", fontFamily: "monospace", resize: "vertical" }}
                  />
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Alt Metin</label>
                  <textarea
                    value={currentHero.subtitle || ""}
                    onChange={(e) => {
                      const heroKey = isEnTab ? "hero_texts_en" : "hero_texts";
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        [heroKey]: { ...(prev[heroKey] || {}), subtitle: e.target.value }
                      }));
                    }}
                    rows={2}
                    style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px", resize: "vertical" }}
                  />
                </div>
              </div>
            </div>

            {/* FAQ Texts */}
            <div style={{ padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
              <h4 style={{ fontSize: "14px", color: C.gold, marginBottom: "16px", fontWeight: 600 }}>Sıkça Sorulan Sorular Metinleri ({selectedLang.toUpperCase()})</h4>
              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Küçük Başlık (Label)</label>
                  <input
                    type="text"
                    value={currentFaqTexts.label || ""}
                    onChange={(e) => {
                      const faqTextsKey = isEnTab ? "faq_texts_en" : "faq_texts";
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        [faqTextsKey]: { ...(prev[faqTextsKey] || {}), label: e.target.value }
                      }));
                    }}
                    style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                  />
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Ana Başlık (HTML Kullanılabilir)</label>
                  <textarea
                    value={currentFaqTexts.heading || ""}
                    onChange={(e) => {
                      const faqTextsKey = isEnTab ? "faq_texts_en" : "faq_texts";
                      setSiteSettings((prev: any) => ({
                        ...prev,
                        [faqTextsKey]: { ...(prev[faqTextsKey] || {}), heading: e.target.value }
                      }));
                    }}
                    rows={2}
                    style={{ width: "100%", padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px", fontFamily: "monospace", resize: "vertical" }}
                  />
                </div>
              </div>
            </div>

            {/* FAQ List Editor */}
            <div style={{ padding: "20px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
                <h4 style={{ fontSize: "14px", color: C.gold, fontWeight: 600 }}>Sıkça Sorulan Sorular Listesi ({selectedLang.toUpperCase()})</h4>
                <button
                  type="button"
                  onClick={() => {
                    const newFaq = { q: isEnTab ? "New Question?" : "Yeni Soru?", a: isEnTab ? "Answer..." : "Cevap..." };
                    const faqsKey = isEnTab ? "faqs_en" : "faqs";
                    setSiteSettings((prev: any) => ({
                      ...prev,
                      [faqsKey]: [...(prev[faqsKey] || []), newFaq]
                    }));
                  }}
                  style={{
                    background: "rgba(201,168,76,0.15)",
                    border: `1px solid ${C.gold}`,
                    color: C.gold,
                    fontSize: "11px",
                    padding: "6px 12px",
                    borderRadius: "15px",
                    cursor: "pointer",
                    fontFamily: "var(--font-inter), sans-serif",
                    fontWeight: 500,
                    transition: "opacity 0.2s"
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.opacity = "0.8"}
                  onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}
                >
                  {isEnTab ? "+ Add New Question" : "+ Yeni Soru Ekle"}
                </button>
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                {currentFaqs.map((faq: any, index: number) => (
                  <div
                    key={index}
                    style={{
                      padding: "16px",
                      borderRadius: "8px",
                      background: "rgba(255,255,255,0.01)",
                      border: "1px solid rgba(255,255,255,0.05)",
                      position: "relative"
                    }}
                  >
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "10px" }}>
                      <span style={{ fontSize: "11px", color: C.gold, fontWeight: 500 }}>{isEnTab ? `Question #${index + 1}` : `Soru #${index + 1}`}</span>
                      <div style={{ display: "flex", gap: "8px" }}>
                        {/* Move Up */}
                        <button
                          type="button"
                          disabled={index === 0}
                          onClick={() => {
                            if (index === 0) return;
                            const faqsKey = isEnTab ? "faqs_en" : "faqs";
                            const newList = [...(siteSettings[faqsKey] || [])];
                            const temp = newList[index];
                            newList[index] = newList[index - 1];
                            newList[index - 1] = temp;
                            setSiteSettings((prev: any) => ({ ...prev, [faqsKey]: newList }));
                          }}
                          style={{
                            background: "transparent",
                            border: "none",
                            color: index === 0 ? "rgba(255,255,255,0.1)" : "rgba(255,255,255,0.4)",
                            fontSize: "11px",
                            cursor: index === 0 ? "not-allowed" : "pointer"
                          }}
                        >
                          ▲
                        </button>
                        {/* Move Down */}
                        <button
                          type="button"
                          disabled={index === currentFaqs.length - 1}
                          onClick={() => {
                            if (index === currentFaqs.length - 1) return;
                            const faqsKey = isEnTab ? "faqs_en" : "faqs";
                            const newList = [...(siteSettings[faqsKey] || [])];
                            const temp = newList[index];
                            newList[index] = newList[index + 1];
                            newList[index + 1] = temp;
                            setSiteSettings((prev: any) => ({ ...prev, [faqsKey]: newList }));
                          }}
                          style={{
                            background: "transparent",
                            border: "none",
                            color: index === currentFaqs.length - 1 ? "rgba(255,255,255,0.1)" : "rgba(255,255,255,0.4)",
                            fontSize: "11px",
                            cursor: index === currentFaqs.length - 1 ? "not-allowed" : "pointer"
                          }}
                        >
                          ▼
                        </button>
                        {/* Delete */}
                        <button
                          type="button"
                          onClick={() => {
                            const confirmMsg = isEnTab ? "Are you sure you want to delete this question?" : "Bu soruyu silmek istediğinize emin misiniz?";
                            if (confirm(confirmMsg)) {
                              const faqsKey = isEnTab ? "faqs_en" : "faqs";
                              const newList = (siteSettings[faqsKey] || []).filter((_: any, idx: number) => idx !== index);
                              setSiteSettings((prev: any) => ({ ...prev, [faqsKey]: newList }));
                            }
                          }}
                          style={{
                            background: "transparent",
                            border: "none",
                            color: "#E8A0A0",
                            fontSize: "11px",
                            cursor: "pointer",
                            fontWeight: 500
                          }}
                        >
                          {isEnTab ? "Delete" : "Sil"}
                        </button>
                      </div>
                    </div>

                    <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                      <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
                        <label style={{ fontSize: "10px", color: C.muted, textTransform: "uppercase" }}>{isEnTab ? "Question" : "Soru"}</label>
                        <input
                          type="text"
                          value={faq.q || ""}
                          onChange={(e) => {
                            const faqsKey = isEnTab ? "faqs_en" : "faqs";
                            const newList = [...(siteSettings[faqsKey] || [])];
                            newList[index] = { ...newList[index], q: e.target.value };
                            setSiteSettings((prev: any) => ({ ...prev, [faqsKey]: newList }));
                          }}
                          style={{ width: "100%", padding: "8px 12px", borderRadius: "6px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "12px" }}
                        />
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
                        <label style={{ fontSize: "10px", color: C.muted, textTransform: "uppercase" }}>{isEnTab ? "Answer" : "Cevap"}</label>
                        <textarea
                          value={faq.a || ""}
                          onChange={(e) => {
                            const faqsKey = isEnTab ? "faqs_en" : "faqs";
                            const newList = [...(siteSettings[faqsKey] || [])];
                            newList[index] = { ...newList[index], a: e.target.value };
                            setSiteSettings((prev: any) => ({ ...prev, [faqsKey]: newList }));
                          }}
                          rows={2}
                          style={{ width: "100%", padding: "8px 12px", borderRadius: "6px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "12px", resize: "vertical" }}
                        />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* ABANDONED CART SETTINGS */}
            <div style={{ marginTop: "32px", padding: "24px", background: "rgba(0,0,0,0.2)", borderRadius: "16px", border: "1px solid rgba(255,255,255,0.04)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
                <h3 style={{ fontSize: "16px", fontWeight: 600, color: C.text, margin: 0 }}>Terk Edilmiş Sayfa Yönetimi</h3>
                <button
                  type="button"
                  onClick={() => setSiteSettings({
                    ...siteSettings,
                    abandoned_cart_settings: {
                      ...siteSettings.abandoned_cart_settings,
                      enabled: siteSettings.abandoned_cart_settings?.enabled !== false ? false : true
                    }
                  })}
                  style={{
                    padding: "6px 16px",
                    borderRadius: "20px",
                    border: "none",
                    background: siteSettings.abandoned_cart_settings?.enabled !== false ? C.gold : "rgba(255,255,255,0.1)",
                    color: siteSettings.abandoned_cart_settings?.enabled !== false ? "#0B0F1A" : C.text,
                    fontSize: "12px",
                    fontWeight: 600,
                    cursor: "pointer",
                    transition: "all 0.2s"
                  }}
                >
                  {siteSettings.abandoned_cart_settings?.enabled !== false ? "Özellik Aktif 🔘" : "Özellik Pasif ⬜"}
                </button>
              </div>
              
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px", marginBottom: "16px" }}>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Mail Gönderme Süresi (Saat)</label>
                  <input
                    type="number"
                    value={siteSettings.abandoned_cart_settings?.email_delay_hours || 12}
                    onChange={(e) => setSiteSettings({ ...siteSettings, abandoned_cart_settings: { ...siteSettings.abandoned_cart_settings, email_delay_hours: Number(e.target.value) } })}
                    style={{ padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                  />
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                  <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>Sayfa Silme Süresi (Saat)</label>
                  <input
                    type="number"
                    value={siteSettings.abandoned_cart_settings?.delete_delay_hours || 72}
                    onChange={(e) => setSiteSettings({ ...siteSettings, abandoned_cart_settings: { ...siteSettings.abandoned_cart_settings, delete_delay_hours: Number(e.target.value) } })}
                    style={{ padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                  />
                  <p style={{ fontSize: "10px", color: C.error, marginTop: "2px" }}>0 yazarsanız otomatik silme devre dışı kalır.</p>
                </div>
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: "6px", marginBottom: "16px" }}>
                <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>E-posta Başlığı</label>
                <input
                  type="text"
                  value={siteSettings.abandoned_cart_settings?.email_subject || ""}
                  onChange={(e) => setSiteSettings({ ...siteSettings, abandoned_cart_settings: { ...siteSettings.abandoned_cart_settings, email_subject: e.target.value } })}
                  style={{ padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px" }}
                />
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                <label style={{ fontSize: "11px", color: C.muted, textTransform: "uppercase" }}>E-posta İçeriği (HTML)</label>
                <textarea
                  value={siteSettings.abandoned_cart_settings?.email_body || ""}
                  onChange={(e) => setSiteSettings({ ...siteSettings, abandoned_cart_settings: { ...siteSettings.abandoned_cart_settings, email_body: e.target.value } })}
                  rows={8}
                  style={{ padding: "10px 14px", borderRadius: "8px", background: C.bg, border: `1px solid ${C.border}`, color: C.text, fontSize: "13px", resize: "vertical", fontFamily: "monospace" }}
                />
              </div>
            </div>

            <button
              onClick={handleSave}
              disabled={settingsSaving}
              style={{
                width: "100%", padding: "15px", borderRadius: "30px", border: "none",
                background: settingsSaving ? "rgba(201,168,76,0.5)" : C.gold, color: "#0B0F1A",
                fontFamily: "var(--font-inter), sans-serif", fontSize: "13px", letterSpacing: "0.12em",
                textTransform: "uppercase", fontWeight: 600, cursor: settingsSaving ? "not-allowed" : "pointer",
                transition: "opacity 0.2s", marginTop: "8px",
              }}
            >
              {settingsSaving ? "Kaydediliyor..." : "Ayarları Kaydet"}
            </button>
          </div>
        )}
      </div>
    </motion.div>
  );
}
